import{_ as t,o as a,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"26. Wages And Allowances","description":"","frontmatter":{"title":"26. Wages And Allowances","eba":"Biomedical Engineers 2025-2028","topics":["wages"]},"headers":[],"relativePath":"ebas/biomedical-engineers/wages/26-wages-and-allowances.md","filePath":"ebas/biomedical-engineers/wages/26-wages-and-allowances.md"}'),s={name:"ebas/biomedical-engineers/wages/26-wages-and-allowances.md"};function r(i,e,l,p,m,h){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_26-wages-and-allowances" tabindex="-1">26. Wages And Allowances <a class="header-anchor" href="#_26-wages-and-allowances" aria-label="Permalink to &quot;26. Wages And Allowances&quot;">​</a></h1><p>The weekly salaries and allowances over the life of the Agreement (incorporating the increases set out in this clause) are contained in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>.</p><p><strong>26.1</strong> The weekly rates of pay outlined in the 2022 Agreement will be increased over the life of the Agreement as follows:</p><p><strong>(a)</strong> from the FFPPOOA 1 August 2024 – 3%;</p><p><strong>(b)</strong> from the FFPPOOA 1 August 2025 – 3%;</p><p><strong>(c)</strong> from the FFPPOOA 1 August 2026 – 3%; and</p><p><strong>(d)</strong> from the FFPPOOA 1 August 2027 – 3%.</p><p><strong>26.2</strong> The above rates of pay will only come into operation on the approval of this Agreement by the Commission in accordance with the Act.</p><p><strong>26.3</strong> All monetary based allowances (e.g. meal allowance) in this Agreement shall be adjusted by the same percentage amount and from the same dates as the percentage movement in wages specified in subclause 26.1.</p><p><strong>26.4</strong> Cash Payments</p><p><strong>(a)</strong> Patience in Bargaining Payment Full-time Employees who are employed by an Employer upon commencement of this Agreement will be entitled to a once-off ‘Patience in Bargaining’ payment of $2,500.</p><p><strong>(b)</strong> Once-off Cash Incentive Payment Full-time Employees who are employed by an Employer upon commencement of this Agreement will be entitled to a once-off cash incentive payment of $5,180.</p><p><strong>(c)</strong> Entitlement</p><p><strong>(i)</strong> The payments at subclauses 26.4(a) and 26.4(b) will be made on a pro-rata basis for part-time and casual Employees as follows:</p><p><strong>(ii)</strong> Part-time Employee – the Employee’s contracted hours, save that where the part-time Employee’s ordinary hours fluctuate because the Employee works additional ordinary shifts (but excluding a permanent variation) an average of the Employee’s ordinary hours over: <strong>(A)</strong> the preceding 12 months; or <strong>(B)</strong> the Employee’s period of service where the Employee has less than 12 months service; will apply where this is more favourable to the Employee; or</p><p><strong>(iii)</strong> Casual Employee – average of the Employee’s ordinary hours of work over the preceding 12 months.</p><p><strong>(iv)</strong> Employees will receive these payments as a lump sum no later than the FFPPOOA the Agreement has been in effect for 30 days. For avoidance of doubt, this 30-day period commences 7 days after the Commission approves this Agreement.</p><p><strong>(d)</strong> Entitlement for Terminated Employees Where an Employee:</p><p><strong>(i)</strong> is employed by an Employer listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> (initial employer) on commencement of the Agreement;</p><p><strong>(ii)</strong> their employment with the initial employer is terminated for any reason; and</p><p><strong>(iii)</strong> commences their employment with another Employer listed in <a href="/eba/ebas/allied-health/appendices/1-list-of-employers.html">Appendix 1</a> (second employer); they are entitled to receive the payments outlined in subclauses 26.4(a) and 26.4(b) from the initial employer. Employees are not entitled to receive a second payment from the second employer.</p>',21)])])}const d=t(s,[["render",r]]);export{g as __pageData,d as default};
